export function initialize(dotNetRef, timeoutMs) {
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    }

    const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];
    events.forEach(e => document.addEventListener(e, resetTimer, { passive: true }));

    // Start the initial timer
    resetTimer();

    return {
        dispose() {
            events.forEach(e => document.removeEventListener(e, resetTimer));
            if (timerId !== null) {
                clearTimeout(timerId);
                timerId = null;
            }
        },
        updateTimeout(newTimeoutMs) {
            timeoutMs = newTimeoutMs;
            resetTimer();
        }
    };
}

